15	function initializeDatabase() {
16	  // Tabela faturamento
17	  db.run(`
18	    CREATE TABLE IF NOT EXISTS faturamento (
19	      id INTEGER PRIMARY KEY AUTOINCREMENT,
20	      data DATE UNIQUE NOT NULL,
21	      total DECIMAL(10,2) NOT NULL CHECK(total > 0),
22	      status BOOLEAN DEFAULT 0,
23	      enviado_em TIMESTAMP,
24	      created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
25	      updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
26	    )
27	  `, (err) => {
28	    if (err) {
29	      console.error('Erro ao criar tabela:', err.message);
30	    } else {
31	      console.log('✅ Tabela "faturamento" pronta');
32	    }
33	  });
34	
35	  // Índices
36	  db.run(`CREATE INDEX IF NOT EXISTS idx_data ON faturamento(data DESC)`);
37	  db.run(`CREATE INDEX IF NOT EXISTS idx_status ON faturamento(status)`);
38	  db.run(`CREATE INDEX IF NOT EXISTS idx_created ON faturamento(created_at DESC)`);
39	}
40	
41	// Função para usar o database
42	function runAsync(sql, params = []) {
43	  return new Promise((resolve, reject) => {
44	    db.run(sql, params, function(err) {
45	      if (err) reject(err);
46	      else resolve({ id: this.lastID, changes: this.changes });
47	    });
48	  });
49	}
50	
51	// Função para queries de leitura
52	function getAsync(sql, params = []) {
53	  return new Promise((resolve, reject) => {
54	    db.get(sql, params, (err, row) => {
55	      if (err) reject(err);
56	      else resolve(row);
57	    });
58	  });
59	}
60	
61	// Função para queries que retornam múltiplas linhas
62	function allAsync(sql, params = []) {
63	  return new Promise((resolve, reject) => {
64	    db.all(sql, params, (err, rows) => {
65	      if (err) reject(err);
66	      else resolve(rows);
67	    });
68	  });
69	}
70	
71	module.exports = {
72	  db,
73	  runAsync,
74	  getAsync,
75	  allAsync
76	};
