3	class Faturamento {
4	  // Listar faturamentos (últimos N dias, opcionalmente filtrar por status)
5	  static async listar(days = 30, status = null) {
6	    let sql = `
7	      SELECT * FROM faturamento
8	      WHERE data >= date('now', '-${days} days')
9	    `;
10	    let params = [];
11	
12	    if (status !== null) {
13	      if (status === 'pending') {
14	        sql += ` AND status = 0`;
15	      } else if (status === 'sent') {
16	        sql += ` AND status = 1`;
17	      }
18	    }
19	
20	    sql += ` ORDER BY data DESC`;
21	
22	    return await allAsync(sql, params);
23	  }
24	
25	  // Obter um faturamento específico
26	  static async obter(id) {
27	    const sql = `SELECT * FROM faturamento WHERE id = ?`;
28	    return await getAsync(sql, [id]);
29	  }
30	
31	  // Criar novo faturamento
32	  static async criar(data, total) {
33	    // Validar data não futura
34	    const today = new Date().toISOString().split('T')[0];
35	    if (data > today) {
36	      throw new Error('Data não pode ser futura');
37	    }
38	
39	    // Validar total > 0
40	    if (total <= 0) {
41	      throw new Error('Total deve ser maior que zero');
42	    }
43	
44	    const sql = `
45	      INSERT INTO faturamento (data, total, status, created_at, updated_at)
46	      VALUES (?, ?, 0, datetime('now'), datetime('now'))
47	    `;
48	    return await runAsync(sql, [data, parseFloat(total)]);
49	  }
50	
51	  // Atualizar faturamento (apenas total)
52	  static async atualizar(id, total) {
53	    // Validar total > 0
54	    if (total <= 0) {
55	      throw new Error('Total deve ser maior que zero');
56	    }
57	
58	    const sql = `
59	      UPDATE faturamento
60	      SET total = ?, updated_at = datetime('now')
61	      WHERE id = ?
62	    `;
63	    return await runAsync(sql, [parseFloat(total), id]);
64	  }
65	
66	  // Deletar faturamento
67	  static async deletar(id) {
68	    const sql = `DELETE FROM faturamento WHERE id = ?`;
69	    return await runAsync(sql, [id]);
70	  }
71	
72	  // Marcar como enviado ao Conta Azul
73	  static async marcarEnviado(id) {
74	    const sql = `
75	      UPDATE faturamento
76	      SET status = 1, enviado_em = datetime('now'), updated_at = datetime('now')
77	      WHERE id = ?
78	    `;
79	    return await runAsync(sql, [id]);
80	  }
81	
82	  // Obter estatísticas (KPIs) para um período
83	  static async obterStats(dataInicio, dataFim) {
84	    const sql = `
85	      SELECT
86	        COALESCE(SUM(total), 0) as total,
87	        COALESCE(AVG(total), 0) as media,
88	        COALESCE(MAX(total), 0) as maior,
89	        COALESCE(MIN(total), 0) as menor,
90	        COUNT(*) as dias
91	      FROM faturamento
92	      WHERE data >= ? AND data <= ?
93	    `;
94	    return await getAsync(sql, [dataInicio, dataFim]);
95	  }
96	
97	  // Obter dados para gráfico (todos os dias no período)
98	  static async obterDadosGrafico(dataInicio, dataFim) {
99	    const sql = `
100	      SELECT data, total
101	      FROM faturamento
102	      WHERE data >= ? AND data <= ?
103	      ORDER BY data ASC
104	    `;
105	    return await allAsync(sql, [dataInicio, dataFim]);
106	  }
107	}
108	
109	module.exports = Faturamento;
110	

